ATTRIBUTE.VALUE:
DELETE FROM DIM_BANK
WHERE LOADDATE >= CAST('$$BUSINESS_DATE' AS DATE)
AND   LOADDATE <  DATEADD(DAY, 1, CAST('$$BUSINESS_DATE' AS DATE));

DELETE FROM STG_TRANSACTION
WHERE LOADDATE >= CAST('$$BUSINESS_DATE' AS DATE)
AND   LOADDATE <  DATEADD(DAY, 1, CAST('$$BUSINESS_DATE' AS DATE));

DELETE FROM STG_CUSTOMER
WHERE LOADDATE >= CAST('$$BUSINESS_DATE' AS DATE)
AND   LOADDATE <  DATEADD(DAY, 1, CAST('$$BUSINESS_DATE' AS DATE));
